.darma-loader-darma-custom-717 {
  color: var(--loader-color, #ec4899);
width: 40px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(currentColor 0 0);
--m:no-repeat radial-gradient(circle closest-side,#0000 92%,currentColor);
background:
var(--c) 0 50%,
var(--c) 50% 50%,
var(--c) 100% 50%;
background-size: 8px calc(50% + 8px);
-webkit-mask: var(--m),var(--m),var(--m);
-webkit-mask-size: 8px 150%;
animation: darma-loader-darma-custom-717-l12 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-717-l12 {
0%,
100% {-webkit-mask-position: 0 50% ,50% 50% ,100% 50% }
20% {-webkit-mask-position: 0 100%,50% 50% ,100% 50% }
40% {-webkit-mask-position: 0 0 ,50% 100%,100% 50% }
60% {-webkit-mask-position: 0 50% ,50% 0 ,100% 100%}
80% {-webkit-mask-position: 0 50% ,50% 50% ,100% 0 }
}

